function solve(grid: number[][], k: number): number {
    const m = grid.length;
    const n = grid[0].length;
    const dist = Array(m).fill(0).map(() => Array(n).fill(Number.MAX_VALUE));
    dist[0][0] = 0;
    const queue: [number, number, number][] = [[0, 0, 0]]; // [row, col, cost]
    const visited = Array(m).fill(0).map(() => Array(n).fill(false));

    while (queue.length > 0) {
        const [row, col, cost] = queue.shift()!;
        visited[row][col] = true;

        // Regular move: right or down
        [0, 1].forEach(dr => {
            const nextRow = row + dr;
            const nextCol = col;
            if (nextRow < m && nextCol < n) {
                const newCost = cost + grid[nextRow][nextCol];
                if (newCost < dist[nextRow][nextCol]) {
                    dist[nextRow][nextCol] = newCost;
                    queue.push([nextRow, nextCol, newCost]);
                }
            }
        });

        // Teleport: find all cells with value <= current cell's value
        const currentVal = grid[row][col];
        for (let i = 0; i < m; i++) {
            for (let j = 0; j < n; j++) {
                if (grid[i][j] <= currentVal && !visited[i][j]) {
                    const newCost = cost;
                    if (newCost < dist[i][j]) {
                        dist[i][j] = newCost;
                        queue.push([i, j, newCost]);
                    }
                }
            }
        }
    }

    return dist[m - 1][n - 1];
}
